<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/shm</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # POSIX 共享内存</span></span>
